  <div class=\"flex justify-between items-center py-1\">\n               <p class=\"font-semibold text-xs\">Total earnings: {{salary.earning}}</p>\n              <p class=\"font-semibold text-xs\">Total deductions:{{salary.deduction}}</p>\n           <!--  </div>\n          <div class=\"flex justify-between items-center py-1\"> -->\n               <p class=\"font-semibold text-xs\">Net salary: {{salary.total}}</p>\n                \n            </div>\n          </div>\n         \n        </div>\n      </div>\n    </div>\n<!-- End modal -->\n  </div>\n</template>\n\n<script>\n\nexport default {\n  props:['url'],\n  data () {\n    return {\n      page_count:0,\n      page:0,\n      total :'',\n      payslips:[],\n      salary:[],\n      payslipitems:[],\n      show:0,\n      success:null,\n      status:'unpaid',\n      checkstatus:''\n    \n    }\n  },\n\n  methods:\n  {\n    getlist(page=1)\n    {\n      axios.get('/accountant/payroll/payslip/list?page='+this.page+'&status='+this.status).then(response => {\n        this.payslips = response.data.data;\n        this.page_count = response.data.meta.last_page;\n        this.total = response.data.meta.total;\n        //console.log(this.templates);    \n      });\n    },\n\n    statuschange(e)\n    {\n      if (e.target.checked) \n                {\n                  this.status='paid';\n                  this.getlist(this.page=1);\n                    //alert(this.status);\n                }\n                else if (!e.target.checked)\n                {\n                  this.status='unpaid';\n                 // alert(this.status);\n                    this.getlist(this.page=1);\n                }\n\n    },\n\n    deletetopic(id) \n    {\n      var thisswal = this;\n      swal({\n        title: 'Are you sure',\n        text: 'Do you want to delete this Payroll ?',\n        icon: \"info\",\n        buttons: [\n          'No',\n          'Yes'\n        ],\n        dangerMode: true,\n      }).then(function(isConfirm) {\n        if (isConfirm) \n        {\n          axios.delete(thisswal.url+'/accountant/payroll/payslip/'+id+'/delete').then(response => {\n             thisswal.success    = response.data.message;\n             thisswal.getlist();\n          });  \n        }\n        else \n        {\n          swal(\"Cancelled\");\n        }\n      });\n    },\n\n    detail(id)\n      {\n        \n        this.show=1;\n        axios.get(this.url+'/accountant/payroll/payslip/'+id+'/editshow').then(response => {\n         \n          this.salary   = response.data.data;\n          this.payslipitems   = this.salary.payslipitems;\n\n          console.log(response); \n             \n        });\n       \n      },\n      closeModal()\n      {\n        this.show=0;\n      },\n\n\n  },\n  \n  created()\n  {   \n    this.getlist();\n  }\n}\n</script>\n\n<style scoped>\n\n.modal-mask {\n  position: fixed;\n  z-index: 9998;\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 100%;\n  background-color: rgba(0, 0, 0, .5);\n  display: table;\n  transition: opacity .3s ease;\n}\n\n.modal-wrapper {\n  display: table-cell;\n  vertical-align: middle;\n    overflow:auto;\n}\n\n.modal-container {\n  margin: 0px auto;\n  padding: 20px 30px;\n  background-color: #fff;\n  border-radius: 2px;\n  box-shadow: 0 2px 8px rgba(0, 0, 0, .33);\n  transition: all .3s ease;\n /* height: 550px;*/\n  overflow:auto;\n}\n\n.modal-header h3 {\n  margin-top: 0;\n  color: #42b983;\n}\n\n.modal-body {\n  margin: 10px 0;\n}\n\n.modal-default-button {\n  float: right;\n}\n\n/*\n * The following styles are auto-applied to elements with\n * transition=\"modal\" when their visibility is toggled\n * by Vue.js.\n *\n * You can easily play with the modal transition by editing\n * these styles.\n */\n\n.modal-enter {\n  opacity: 0;\n}\n\n.modal-leave-active {\n  opacity: 0;\n}\n\n.modal-enter .modal-container,\n.modal-leave-active .modal-container {\n  -webkit-transform: scale(1.1);\n  transform: scale(1.1);\n}\n\n.text-danger\n{\n  color:red;\n}\n</style>"],"sourceRoot":""}]);
